# Attach Attach ### Быстрый старт Быстрый старт ```tsx
import React from 'react';
import { Attach } from '@salutejs/plasma-web';

export function App() {
    const handleFileSelect = (event) => {
        const file = event.target.files[0];
        console.log('Выбран файл:', file.name);
    };

    return (
        <Attach
            view="accent"
            text="Upload file"
            onChange={handleFileSelect}
        />
    );
}
```

### Управление внешним видом и типом компонента Управление внешним видом и типом компонента С помощью свойств: `view`  - задается внешний вид `buttonType`  - можно менять вид кнопки:  `button` ,  `iconButton` ```tsx
import React from 'react';
import { Attach } from '@salutejs/plasma-web';

export function App() {
    return (
        <div style={{ display: "flex", flexDirection: "column", gap: "32px"}}>
            <Attach view="accent" buttonType='button' text="Upload file" />
            <Attach view="secondary" buttonType='iconButton'/>
        </div>
    );
}
```

### Управление подсказкой с помощью свойства helperText Управление подсказкой с помощью свойства helperText Вид  `helperText`  задается с помощью свойства  `helperTextView` . Возможные значения свойства: `default`  – по умолчанию; `negative`  – ошибка. ```tsx
import React from 'react';
import { Attach } from '@salutejs/plasma-web';

export function App() {
    return (
        <div style={{ padding: "1rem" }}>
            <Attach helperTextView="default" helperText="Caption" />
            <Attach helperTextView="negative" helperText="Caption" />
        </div>
    );
}
```

### Расположение элементов Расположение элементов Расположение регулируется свойством Flow, которое позволяет размещать элементы вертикально,
горизонтально или автоматически (перенес на следующую строку при нехватке ширины компонента Attach). ```tsx
import React from 'react';
import { Attach } from '@salutejs/plasma-web';

export function App() {
    return (
        <div style={{ display: "flex", flexDirection: "column", gap: "50px"}}>
            <Attach style={{ width: "400px" }} helperText='Auto' flow="auto" />
            <Attach style={{ width: "400px" }} helperText='Horizontal' flow="horizontal" />
            <Attach style={{ width: "400px" }} helperText='Vertical' flow="vertical" />
        </div>
    );
}
```

### Attach с несколькими файлами Attach с несколькими файлами С помощью свойств: `multiple`  - добавляет возможность прикреплять несколько файлов ```tsx
