# Breadcrumbs Breadcrumbs Props (свойства) для компонента Breadcrumbs: [{"name":"view","type":{"name":"enum","raw":"\"default\"","value":[{"value":"\"default\""}]}},{"name":"size","type":{"name":"enum","raw":"\"m\" | \"s\" | \"l\" | \"xs\"","value":[{"value":"\"m\""},{"value":"\"s\""},{"value":"\"l\""},{"value":"\"xs\""}]}},{"name":"separator","type":{"name":"ReactNode"}},{"name":"items","type":{"name":"BreadcrumbsItem[]"}},{"name":"showItems","type":{"name":"number"}}] # Типизация элементов Типизация элементов Параметр  `items`  является обязательным и поддерживает следующие типы: ```tsx
type Items =
    | {
          /**
           * Обработчик клика на элемент
           */
          onClick?: () => void;
          /**
           * Элемент заголовка
           */
          title: string;
          /**
           * Элемент выключен
           */
          disabled?: boolean;
      }
    | {
          /**
           * Ссылка на страницу ( если не указана, то ссылка не кликабельна )
           */
          href?: string;
          /**
           * Элемент заголовка
           */
          title: string;
          /**
           * Элемент выключен
           */
          disabled?: boolean;
      }
    | {
          /**
           * Функция рендера элемента
           */
          renderItem: () => ReactNode;
      };
```

При использовании одного из трёх вариантов, свойства остальных будут не доступны. # Пример Пример ```tsx
import React from 'react';
import { Breadcrumbs } from '@salutejs/plasma-web';

export function App() {
    const items = [
        { title: 'Home', href: '/' },
        { title: 'Without link' },
        { title: 'Disabled', disabled: true },
        { title: 'Disabled with link', href: '/', disabled: true },
        {
            title: 'On Click',
            onClick: () => {
                alert('On Click');
            },
        },
        { renderItem: () => <span style={{ cursor: 'pointer' }}>Custom </span> },
        { title: 'Main' },
    ];

    return (
        <div>
            <Breadcrumbs items={items} />
        </div>
    );
}
```

