# Button Button Кнопки могут отображаться в нескольких размерах и цветах, могут содержать текст и/или иконку. Props (свойства) для компонента Button: [{"name":"view","type":{"name":"enum","raw":"\"clear\" | \"default\" | \"secondary\" | \"primary\" | \"accent\" | \"warning\" | \"dark\" | \"success\" | \"critical\" | \"black\" | \"white\"","value":[{"value":"\"clear\""},{"value":"\"default\""},{"value":"\"secondary\""},{"value":"\"primary\""},{"value":"\"accent\""},{"value":"\"warning\""},{"value":"\"dark\""},{"value":"\"success\""},{"value":"\"critical\""},{"value":"\"black\""},{"value":"\"white\""}]}},{"name":"size","type":{"name":"enum","raw":"\"m\" | \"s\" | \"l\" | \"xs\" | \"xl\" | \"xxs\"","value":[{"value":"\"m\""},{"value":"\"s\""},{"value":"\"l\""},{"value":"\"xs\""},{"value":"\"xl\""},{"value":"\"xxs\""}]}},{"name":"disabled","type":{"name":"boolean"}},{"name":"focused","type":{"name":"boolean"}},{"name":"stretching","type":{"name":"enum","raw":"\"filled\" | \"fixed\" | \"auto\"","value":[{"value":"\"filled\""},{"value":"\"fixed\""},{"value":"\"auto\""}]}},{"name":"text","type":{"name":"string"}},{"name":"contentLeft","type":{"name":"ReactNode"}},{"name":"contentPlacing","type":{"name":"enum","raw":"ContentPlacing","value":[{"value":"\"default\""},{"value":"\"relaxed\""}]}},{"name":"additionalContent","type":{"name":"ReactNode"}},{"name":"isLoading","type":{"name":"boolean"}},{"name":"loader","type":{"name":"ReactNode"}},{"name":"stretch","type":{"name":"boolean"}},{"name":"square","type":{"name":"boolean"}},{"name":"pin","type":{"name":"enum","raw":"\"square-square\" | \"square-clear\" | \"clear-square\" | \"clear-clear\" | \"clear-circle\" | \"circle-clear\" | \"circle-circle\"","value":[{"value":"\"square-square\""},{"value":"\"square-clear\""},{"value":"\"clear-square\""},{"value":"\"clear-clear\""},{"value":"\"clear-circle\""},{"value":"\"circle-clear\""},{"value":"\"circle-circle\""}]}},{"name":"appearance","type":{"name":"enum","raw":"\"default\" | 