Тип выбора комбобокса - одиночный или множественный зависит от типа  `value`  и  `onChange` . В одиночном value -  `string` , в множественном -  `Array<string>` . ## Примеры Примеры ```tsx
import React from 'react';
import { Combobox } from '@salutejs/plasma-web';

export function App() {
   const [value, setValue] = useState<string>('');

    const items = [
        {
            value: 'north_america',
            label: 'Северная Америка',
        },
        {
            value: 'south_america',
            label: 'Южная Америка',
            items: [
                {
                    value: 'brazil',
                    label: 'Бразилия',
                },
                {
                    value: 'argentina',
                    label: 'Аргентина',
                },
            ],
        },
    ];

    return (
        <div style={{ display: "flex", gap: "30px", height: "300px" }}>
            <div style={{ width: "300px" }}>
                <Combobox
                    items={items}
                    value={value}
                    onChange={setValue}
                    placeholder="Placeholder"
                    label="Label"
                    helperText="Helper text"
                />
            </div>
        </div>
    );
}
```

