## DatePickerRange DatePickerRange ### Быстрый старт Быстрый старт Компонент  `DatePickerRange`  представляет собой  `Range`  с выпадающим календарем.
Календарь может быть одиночным или двойным. За это отвечает свойство  `isDoubleCalendar` . ```tsx
import React, {useState} from 'react';
import { DatePickerRange, IconButton } from '@salutejs/plasma-web';
import { IconDone } from '@salutejs/plasma-icons';

type DateType = Date | string | undefined | null

export function App() {
    const [dateValue, setDate] = useState<[DateType, DateType]>([new Date(), null]);
    const [originalDateValue, setOriginalDate] = useState<[DateType, DateType]>([new Date(), null]);
    const [isoDateValue, setIsoDate] = useState<[string?, string?]>([new Date().toISOString(), '']);

    const valueSetter = <T extends unknown, P extends React.Dispatch<React.SetStateAction<any>>>(
        value: T,
        sideOfDate: 'start' | 'end',
        setter: P,
    ) => {
        setter((prevValue) => {
            if (sideOfDate === 'start') {
                return [value, prevValue[1]];
            }

            return [prevValue[0], value];
        });
    };

    const handleChangeValue = (sideOfDate: 'start' | 'end') => (
        _: React.SyntheticEvent<HTMLInputElement> | null,
        value?: string,
        originalDate?: Date | string | null,
        isoDate?: string,
    ) => {
        valueSetter(value, sideOfDate, setDate);
        valueSetter(originalDate, sideOfDate, setOriginalDate);
        valueSetter(isoDate, sideOfDate, setIsoDate);
    };

    const ActionButton = () => {
        return (
            <IconButton view="clear" size="l">
                <IconDone size="s" />
            </IconButton>
        );
    };

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '3rem' }}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.25rem' }}>
                <p>Значение date:<br/> {dateValue.map(String).join(' --- ')}</p>
                <p>Значение originalDate:<br/> {originalDateValue.map(String).join(' --- ')}</p>
                <p>Значение isoDate:<br/> {isoDateValue.join(' --- ')}</p>
            </div>

            <DatePickerRange
                onChangeFirstValue={handleChangeValue('start')}
                onChangeSecondValue={handleChangeValue('end')}
                onCommitFirstDate={console.log}
                onCommitSecondDate={console.log}
                label="Неконтролируемый RangeDatePicker"
                format="DD.MM.YYYY"
                lang="ru"
                placement="bottom"
                isDoubleCalendar
                usePortal
                maskWithFormat
                size="l"
                leftHelper="Подсказка к полю"
                firstPlaceholder="Введите дату 1"
                secondPlaceholder="Введите дату 2"
                contentRight={<ActionButton />}
            />
        </div>
    );
}
```

