type FormattedValues = {
    originalDate?: Date;
    isoDate?: string;
};

export function App() {
    const [dateValue, setDate] = useState<Date | string | undefined>(new Date());
    const [originalDateValue, setOriginalDate] = useState<Date | string | null | undefined>(new Date());
