                <p>Значение originalDate: {String(originalDateValue)}</p>
                <p>Значение isoDate: {isoDateValue}</p>
            </div>

            <DateTimePicker
                value={dateValue}
                onChangeValue={handleChangeValue}
                onCommitDate={console.log}
                label="Контролируемый DateTimePicker"
                dateFormat="DD.MM.YYYY"
                timeFormat="HH:mm:ss"
                maskWithFormat
                lang="ru"
                contentRight={<IconDone size="s" />}
                placement="bottom"
                usePortal
