            <DateTimePicker
                label="Лейбл"
                leftHelper="Подсказка к полю"
                placeholder="Введите дату"
                contentRight={<ActionButton />}
                hasRequiredIndicator
                required
                requiredPlacement="right"
            />
        </div>
    );
}
