export function App() {
    return (
        <div style={{ display: 'flex', flexWrap: 'wrap' }}>
            <EmbedIconButton size="s" view="default">
                <IconClose color="inherit" />
            </EmbedIconButton>
            <EmbedIconButton size="s" view="accent">
                <IconClose color="inherit" />
            </EmbedIconButton>
            <EmbedIconButton size="s" view="secondary">
                <IconClose color="inherit" />
            </EmbedIconButton>
            <EmbedIconButton size="s" view="clear">
                <IconClose color="inherit" />
            </EmbedIconButton>
            <EmbedIconButton size="s" view="positive">
                <IconClose color="inherit" />
            </EmbedIconButton>
            <EmbedIconButton size="s" view="warning">
                <IconClose color="inherit" />
            </EmbedIconButton>
            <EmbedIconButton size="s" view="negative">
                <IconClose color="inherit" />
            </EmbedIconButton>
        </div>
    );
}
```

