# Flow Flow Универсальный контейнер для упорядоченного размещения вложенных компонентов (например, медиафайлы, карточки или блоки текста). ## Flow Flow Props (свойства) для компонента Flow: [{"name":"className","type":{"name":"string"}},{"name":"style","type":{"name":"CSSProperties"}},{"name":"orientation","type":{"name":"enum","raw":"\"horizontal\" | \"vertical\"","value":[{"value":"\"horizontal\""},{"value":"\"vertical\""}]}},{"name":"arrangement","type":{"name":"enum","raw":"\"center\" | \"start\" | \"end\" | \"spaceBetween\" | \"spaceAround\"","value":[{"value":"\"center\""},{"value":"\"start\""},{"value":"\"end\""},{"value":"\"spaceBetween\""},{"value":"\"spaceAround\""}]}},{"name":"alignment","type":{"name":"enum","raw":"\"center\" | \"start\" | \"end\"","value":[{"value":"\"center\""},{"value":"\"start\""},{"value":"\"end\""}]}},{"name":"mainAxisGap","type":{"name":"string | number"}},{"name":"crossAxisGap","type":{"name":"string | number"}},{"name":"itemsPerLine","type":{"name":"number"}}] ## Использование Использование По умолчанию компонент  `Flow`  отображается на основе  `display: flex; flex-wrap: wrap` ,
при указании  `itemsPerLine`  компонент переходит на  `display: flex; flex-wrap: nowrap`  с превентивным разбиением на колонки/столбцы. ## Примеры Примеры ### Горизонтальное отображение с переполнением Горизонтальное отображение с переполнением ```tsx
import React from 'react';
import { Flow } from '@salutejs/plasma-web';

export function App() {
    const numbers = ['one', 'two', 'three', 'four', 'five', 'six'];

    const style = (index) => ({
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        width: `${2 + numbers[index].length}ch`,
        height: '25px',
        backgroundColor: '#999',
        borderRadius: '10px',
    });

    return (
        <div>
            <Flow mainAxisGap="0.5ch" crossAxisGap="1ch" style={{ width: '15ch' }} >
                {Array(6)
                    .fill(0)
                    .map((_, i) => (<div key={i} style={style(i)}>{numbers[i]}</div>))}
            </Flow>
        </div>
    );
}
```

