import ReactDOM from 'react-dom';
import { ModalsProvider } from '@salutejs/plasma-web';

import { App } from './App';

ReactDOM.render(
    <ModalsProvider>
        <App />
    </ModalsProvider>,
    document.getElementById('root')
);
```

### Вызов модального окна Вызов модального окна После подключения  `ModalsProvider`  поместите компонент  `Modal`  туда, где необходимо применить модальное окно: ```tsx
import React from 'react';
import { Modal, Headline3, P1, Button } from '@salutejs/plasma-web';

export function App() {
    const [isOpen, setIsOpen] = React.useState(false);

    const close = React.useCallback(() => {
      setIsOpen(false);
    });

    return (
        <div>
            <Button text="Открыть модальное окно" onClick={() => setIsOpen(!isOpen)} />
            <Modal opened={isOpen} onClose={close}>
                <Headline3 mb={10}>Модальное окно</Headline3>
                <P1>Содержимое модального окна.</P1>
                <Button text="Закрыть" onClick={close} />
            </Modal>
        </div>
    );
}
```

