# ModalBase ModalBase Компонент ModalBase во многом схож с PopupBase, добавляет при этом подложку( `overlay` ), а также блокирует  `scroll`  и  `focus` . ### Быстрый старт Быстрый старт Перед использованием убедитесь, что  `PopupBaseProvider`  подключен. ```tsx
import React from 'react';
import { surfaceSolid02 } from '@salutejs/plasma-tokens-web';
import { SSRProvider, Button, ModalBase, PopupBaseProvider } from '@salutejs/plasma-web';

export function App() {
    const [isOpenA, setIsOpenA] = React.useState(false);
    const [isOpenB, setIsOpenB] = React.useState(false);

    return (
        <SSRProvider>
            <PopupBaseProvider>
                <div style={{ height: "300px" }}>
                    <div style={{ display: 'flex', flexDirection: 'column' }}>
                        <Button text="Открыть A" onClick={() => setIsOpenA(true)} />
                    </div>
                    <ModalBase
                        id="modalA"
                        onClose={() => setIsOpenA(false)}
                        opened={isOpenA}
                        placement="center"
                        offset={[0, 0]}
                    >
                        <div style={{ background: `${surfaceSolid02}`, padding: "1rem" }}>
                            <Button onClick={() => setIsOpenA(false)}>Close</Button>
                            <Button text="Открыть B" onClick={() => setIsOpenB(true)} />
                            Content
                        </div>
                        <ModalBase
                            id="modalB"
                            onClose={() => setIsOpenB(false)}
                            opened={isOpenB}
                            placement="right"
                            offset={[0, 0]}
                        >
                            <div style={{ background: `${surfaceSolid02}`, padding: "1rem" }}>
                                <Button onClick={() => setIsOpenB(false)}>Close</Button>
                                Content
                            </div>
                        </ModalBase>
                    </ModalBase>
                </div>
            </PopupBaseProvider>
        </SSRProvider>
    );
}
```

