# NavigationDrawer NavigationDrawer Props (свойства) для компонента NavigationDrawer: [{"name":"view","type":{"name":"enum","raw":"\"default\"","value":[{"value":"\"default\""}]}},{"name":"size","type":{"name":"enum","raw":"\"m\" | \"s\"","value":[{"value":"\"m\""},{"value":"\"s\""}]}},{"name":"mode","type":{"name":"enum","raw":"\"overlay\" | \"static\" | \"drawer\"","value":[{"value":"\"overlay\""},{"value":"\"static\""},{"value":"\"drawer\""}]}},{"name":"opened","type":{"name":"boolean"}},{"name":"onHide","type":{"name":"(() => void)"}},{"name":"header","type":{"name":"ReactNode"}},{"name":"footer","type":{"name":"ReactNode"}},{"name":"children","type":{"name":"ReactNode"}},{"name":"sections","type":{"name":"SectionItem<true>[] | SectionItem<false>[]"}},{"name":"withContentLeft","type":{"name":"true"}}] ## Использование Использование NavigationDrawer — это компонент навигационного меню, который может отображаться в трех режимах  `mode` : `static`  — статичное меню слева от контента `drawer`  — выдвижное меню поверх контента без затемнения фона `overlay`  — модальное меню поверх контента с затемнением фона ### Структура меню Структура меню Меню состоит из секций, каждая из которых может содержать: `label`  Заголовок секции (опционально) `hasDivider`  Отображать ли разделитель. По умолчанию  `false` . Разделитель отображается, только если не указан заголовок `items`  Список элементов меню ### Элементы меню Элементы меню Каждый элемент меню может содержать: `label`  Текст `icon`  Иконку (при включенном  `withContentLeft` ) `contentLeft`  Контент слева (вместо иконки, при включенном  `withContentLeft` ) `counter`  Счетчик `hasIndicator`  Индикатор `onClick`  Колбек при нажатии на меню `href`  Ссылка `target`  Для ссылки ## Примеры Примеры ```tsx
import React from 'react';
import { NavigationDrawer } from '@salutejs/plasma-web';

export function App() {
    const sections = [{
        items: [
