```tsx
import React, { useState, useRef, useEffect } from 'react';
import { NavigationDrawer } from '@salutejs/plasma-web';
import { IconBlankOutline } from '@salutejs/plasma-icons';

export function App() {
    const [isOpen, setIsOpen] = useState(false);

    const ref = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (ref.current) {
            const sidebar = ref.current.childNodes[0] as HTMLDivElement;
            sidebar.onmouseenter = () => {
                setIsOpen(true);
            };
            sidebar.onmouseleave = () => {
                setIsOpen(false);
            };
        }
    }, [ref]);

    return (
        <div
            style={{
                width: 500,
                height: 300,
                position: 'relative',
                overflow: 'hidden',
                transform: 'translateZ(0)',
            }}
        >
            <NavigationDrawer
                mode="drawer"
                opened={isOpen}
                ref={ref}
                sections={[
                    {
                        hasDivider: false,
                        items: [
                            {
                                label: 'Пункт меню',
                                action: () => console.log('Клик'),
                                icon: <IconBlankOutline />,
                            }
                        ]
                    }
                ]}
            >
                <div style={{ padding: '20px' }}>
                    <p>Основной контент</p>
                </div>
            </NavigationDrawer>
        </div>
    );
}
