            title: 'Входящий вызов',
            icon: <IconBell color="inherit" size="xs" />,
            children: 'Принять?',
            view: 'positive',
            textColor: 'black',
            titleColor: 'blue'
        }, 3000);
    }, []);

    const handleHide = useCallback(() => {
        closeNotification('incoming-call');
    }, []);

    return (
        <NotificationsProvider>
            <ButtonGroup isCommonButtonStyles={false}>
                <Button view="accent" text="Показать оповещение" onClick={handleShow} />
                <Button view="secondary" text="Скрыть оповещение" onClick={handleHide} />
            </ButtonGroup>
        </NotificationsProvider>
    );
}
```

### Управление шириной уведомления Управление шириной уведомления Для управления шириной компонента доступны следующие свойства: `width`  — устанавливает ширину компонента. `maxWidth`  — устанавливает максимальную ширину компонента. Оба свойства принимает любые действительные CSS значения для  width  и  maxWidth ```tsx
import React, { useCallback } from 'react';
import { IconBell } from '@salutejs/plasma-icons';
import { Button, ButtonGroup, addNotification, closeNotification, NotificationsProvider } from '@salutejs/plasma-web';

export function App() {
    const handleShow = useCallback(() => {
        addNotification({
            id: 'incoming-call',
            title: 'Входящий вызов',
            icon: <IconBell color="inherit" size="xs" />,
            children: 'Задача организации, в особенности же сплочённость команды профессионалов требует определения и уточнения глубокомысленных рассуждений.',
            view: 'positive',
            width: 'fit-content',
            maxWidth: '30rem'
        }, 3000);
    }, []);

    const handleHide = useCallback(() => {
        closeNotification('incoming-call');
    }, []);

    return (
        <NotificationsProvider>
            <ButtonGroup isCommonButtonStyles={false}>
                <Button view="accent" text="Показать оповещение" onClick={handleShow} />
                <Button view="secondary" text="Скрыть оповещение" onClick={handleHide} />
            </ButtonGroup>
        </NotificationsProvider>
    );
}
```

