## Навигационные кнопки Навигационные кнопки С помощью свойств  `leftContent`  и  `rightContent`  можно разместить произвольный контент по бокам от блока страниц.
Например, кнопки навигации к первой, предыдущей, следующей и последней страницам: ```tsx
import React, { useState } from 'react';
import { Pagination, IconButton } from '@salutejs/plasma-web';
import {
    IconDoubleDisclosureLeft,
    IconDisclosureLeftOutline,
    IconDisclosureRightOutline,
    IconDoubleDisclosureRight,
} from '@salutejs/plasma-icons';

export function App() {
    const count = 2000;
    const perPage = 20;
    const [page, setPage] = useState(1);

    const lastPage = Math.ceil(count / perPage);

    const leftContent = (
        <>
            <IconButton view="clear" size="xs" onClick={() => setPage(1)}>
                <IconDoubleDisclosureLeft color="inherit" size="xs" />
            </IconButton>
            <IconButton view="clear" size="xs" onClick={() => setPage((p) => Math.max(1, p - 1))}>
                <IconDisclosureLeftOutline color="inherit" size="xs" />
            </IconButton>
        </>
    );

    const rightContent = (
        <>
            <IconButton view="clear" size="xs" onClick={() => setPage((p) => Math.min(lastPage, p + 1))}>
                <IconDisclosureRightOutline color="inherit" size="xs" />
            </IconButton>
            <IconButton view="clear" size="xs" onClick={() => setPage(lastPage)}>
                <IconDoubleDisclosureRight color="inherit" size="xs" />
            </IconButton>
        </>
    );

    return (
        <div>
            <Pagination
                size="xs"
                slots={9}
                count={count}
                perPage={perPage}
                value={page}
                leftContent={leftContent}
                rightContent={rightContent}
                onChange={(newPage) => newPage !== undefined && setPage(newPage)}
            />
        </div>
    );
}
```

## Контролируемый режим Контролируемый режим Компонент поддерживает контролируемый режим через свойства  `value`  и  `perPage` .
Колбэк  `onChange`  вызывается с новым номером страницы и текущим количеством элементов на странице: ```tsx
import React, { useState } from 'react';
import { Pagination } from '@salutejs/plasma-web';

export function App() {
    const [page, setPage] = useState(1);
    const [perPage, setPerPage] = useState(20);

    return (
        <div style={{ display: 'flex', gap: '1rem', flexDirection: 'column' }}>
            <Pagination
                size="xs"
                slots={9}
                count={2000}
                value={page}
                perPage={perPage}
                hasPerPage
                hasQuickJump
                onChange={(newPage, newPerPage) => {
                    if (newPage !== undefined) setPage(newPage);
                    if (newPerPage !== undefined) setPerPage(newPerPage);
                }}
            />
            <div>Страница: {page}, элементов на странице: {perPage}</div>
        </div>
    );
}
```

