## Подключение анимации Подключение анимации Для подключения анимации нужно добавить параметр  `withAnimation` .
Само управление происходит с помощью классов через переменные  `endAnimation` ,  `endTransition`  из объекта  `popupBaseClasses`  для  `PopupBase` .
Для добавления анимации необходимо использовать класс  `.popup-base-root`  через переменную  `popupBaseClasses.root`  из пакета. Пример: ```tsx
const StyledPopupTransition = styled(PopupBase)`
    && > .${popupBaseClasses.root} {
        opacity: 1;
        transition: opacity 0.5s 0.1s;
    }

    &&.${popupBaseClasses.endTransition} > .${popupBaseClasses.root} {
        opacity: 0;
        transition: opacity 0.5s 0.1s;
    }
`;
```

или ```tsx
const StyledPopupAnimation = styled(PopupBase)`
    && > .${popupBaseClasses.root} {
        animation: fadeIn 1s forwards;
    }

    &&.${popupBaseClasses.endAnimation} > .${popupBaseClasses.root} {
        animation: fadeOut 1s forwards;
    }

    @keyframes fadeIn {
        from {
            opacity: 0;
        }

        to {
            opacity: 1;
        }
    }

    @keyframes fadeOut {
        from {
            opacity: 1;
        }

        to {
            opacity: 0;
        }
    }
`;
```

И в самом компоненте: ```tsx
    const [isOpen, setIsOpen] = React.useState(false);

    return (
        <>
            <div>
                <Button
                    style={{
                        marginTop: "1rem",
                        width: "15rem"
                    }}
                    text="Открыть"
                    onClick={() => setIsOpen(true)}
                />
            </div>
            <StyledPopupAnimation
                id="popup-id"
                withAnimation
                frame="document"
                opened={isOpen}
                placement="center"
                offset={[0, 0]}
            >
                <div>
                    <Button onClick={() => setIsOpen(false)}>Close</Button>
                </div>
            </StyledPopupAnimation>
