```

# Segment Segment Набор компонентов для создания группы сегментов.
Структура для сегментов похожа на структуру маркированных списков. ### Быстрый старт Быстрый старт Оберните в  `SegmentProvider`  компонент, в котором будут использованы SegmentGroup с SegmentItem.
Внутри данного провайдера есть доступ к хуку  `useSegment` . Можно задать выбранные по умолчанию сегменты с помощью свойства  `defaultSelected` .
Оно передается в  `SegmentProvider` , в виде массива  `value`  элементов. ```tsx
import React from 'react';
import { SegmentGroup, SegmentItem, SegmentProvider, useSegment } from '@salutejs/plasma-web';

export function App() {
    const items = Array(4).fill(0);

    const SegmentTemplate = () => {
        const {selectedSegmentItems} = useSegment();

        return (
            <>
                <div>Выбранный элемент: {selectedSegmentItems.join(', ')}</div>
                <br />
                <SegmentGroup hasBackground pilled clip={false}>
                    {items.map((_, i) => (
                        <SegmentItem
                            label={`Label ${i}`}
                            value={`label_${i}`}
                            key={`label_${i}`}
                            view='default'
                            pilled
                        />
                    ))}
                </SegmentGroup>
            </>
        )
    }

    return (
        <div style={{ display: "block" }} >
            <SegmentProvider defaultSelected={['label_1']}>
                <SegmentTemplate/>
            </SegmentProvider>
        </div>
    );
}
```

Для управляемого режима используйте свойства  `selected`  и  `onChangeSelected` . ```tsx
import React, { useState } from 'react';
import { SegmentGroup, SegmentItem, SegmentProvider, useSegment } from '@salutejs/plasma-web';

export function App() {
    const items = Array(4).fill(0);
    const [selected, setSelected] = useState(['label_1']);

    const handleChangeSelected = (selectedLabel) => {
        setSelected((prevState) => {
            const newState = [...prevState];
            const existingIndex = prevState.indexOf(selectedLabel);

            if (existingIndex !== -1) {
                newState.splice(existingIndex, 1);
            } else {
                newState.push(selectedLabel);
            }

            return newState;
        });
    };

    const SegmentTemplate = () => {
        const {selectedSegmentItems} = useSegment();

        return (
            <>
                <div>Выбранный элемент: {selectedSegmentItems.join(', ')}</div>
                <br />
                <SegmentGroup hasBackground pilled clip={false}>
                    {items.map((_, i) => (
                        <SegmentItem
                            label={`Label ${i}`}
                            value={`label_${i}`}
                            key={`label_${i}`}
                            view='default'
                            pilled
                        />
                    ))}
                </SegmentGroup>
            </>
        )
    }

    return (
        <div style={{ display: "block" }} >
            <SegmentProvider selected={selected} onChangeSelected={handleChangeSelected}>
                <SegmentTemplate/>
            </SegmentProvider>
        </div>
    );
}
```

