Пропс  `renderValue`  для кастомной настройки  `value`  внутри таргета. Принимает коллбэк с двумя параметрами:  `value`  и  `label` . ```tsx
import React from 'react';
import { Select } from '@salutejs/plasma-web';

export function App() {
    const [singleValue, setSingleValue] = useState('');

    const items = [
        {
            value: 'north_america',
            label: 'Северная Америка',
        },
