                    label: 'Бразилия',
                },
                {
                    value: 'argentina',
                    label: 'Аргентина',
                },
            ],
        },
    ];

    const renderValue = (itemData): string => {
        if (!Array.isArray(itemData)) {
            return `${itemData.value} - ${itemData.label}`;
        }

        return '';
    };

    return (
        <div style={{ height: '300px' }}>
            <div style={{ width: '300px' }}>
                <Select
                    items={items}
                    label="Label"
                    placeholder="Placeholder"
                    value={singleValue}
                    onChange={setSingleValue}
                    renderValue={renderValue}
                />
            </div>
        </div>
    );
}
```

`renderTarget`  - для кастомной настройки таргета в Select. Принимает коллбэк с одним параметром:  `value` .
Пропс  `renderItem`  для кастомной настройки айтема в выпадающем списке. Принимает коллбэк с двумя параметрами:  `value`  и  `label` .
В примере использован другой наш компонент - Cell. ```tsx
import React from 'react';
import { Select, Cell } from '@salutejs/plasma-web';

export function App() {
    const [multipleValue, setMultipleValue] = useState([]);

    const items = [
        {
            value: 'north_america',
            label: 'Северная Америка',
        },
        {
            value: 'south_america',
            label: 'Южная Америка',
        },
    ];

    const renderTarget = (itemData, opened) => {
        console.log(opened);
        if (Array.isArray(itemData)) {
            if (itemData.length === 0) {
                return (
                    <div style={{ padding: '0.5rem 0' }}>
                        <Cell
                            view="default"
                            title="Выберите страну"
                            subtitle="Subtitle"
                            label="Label"
                        />
                    </div>
                );
            }

            const title = itemData.map((item) => item.label).join(', ');

            return (
                <div style={{ padding: '0.5rem 0.75rem' }}>
                    <Cell view="default" title={title} subtitle="Subtitle" label="Label" />
                </div>
            );
        }
    }

    const renderItem = ({ value, label }) => (
        <Cell
            view="default"
            title={label}
            label="Top left"
            contentRight={<Cell view="default" title="Bottom right" label="Top right" />}
        />
    )

    return (
        <div style={{ height: '300px' }}>
           <div style={{ width: '400px' }}>
                <Select
                    items={items}
                    value={multipleValue}
                    onChange={setMultipleValue}
                    multiselect
                    renderTarget={renderTarget}
                    renderItem={renderItem}
                />
            </div>
        </div>
    );
}
```

`renderSelectionIcon`  - свойство для кастомной настройки иконки выбора элемента. Принимает коллбэк с одним параметром:  `selected` . ```tsx
export function App() {
