## Поиск совпадений с функцией подсветки символов Поиск совпадений с функцией подсветки символов :::tips
 `Combobox`  - уже имеет механизм поиска и фильтрацию из коробки.
::: Данный пример показывает реализацию подсветки (highlighting) символов в найденных элементах в режиме  `treeView` . ```tsx
import React, { useState } from 'react';
import { Select, TextField } from '@salutejs/plasma-web';
import { IconCloseCircleOutline } from '@salutejs/plasma-icons';

export function App() {
    const items = [
        {
            value: 'beijing',
            label: 'Пекин',
        },
        {
            value: 'shanghai',
            label: 'Шанхай',
        },
        {
            value: 'tokyo',
            label: 'Токио',
        },
        {
            value: 'osaka',
            label: 'Осака',
        },
        {
            value: 'delhi',
            label: 'Дели',
        },
        {
            value: 'mumbai',
            label: 'Мумбаи',
        },
        {
            value: 'seoul',
            label: 'Сеул',
        },
        {
            value: 'busan',
            label: 'Пусан',
        },
        {
            value: 'bangkok',
            label: 'Бангкок',
        },
        {
            value: 'phuket',
            label: 'Пхукет',
        },
    ];

    const [textValue, setTextValue] = useState('');

    function highlightText(label: string, highlight: string): React.ReactNode {
        if (!highlight.trim()) return label;
        const re = new RegExp('(' + highlight + ')', 'ig');
        const parts = label.split(re);
        return (
            <>
                {parts.map((part, i) =>
                    part.toLowerCase() === highlight.toLowerCase() ? (
                        <mark key={i} style={{ backgroundColor: '#ffeb3b' }}>
                            {part}
                        </mark>
                    ) : (
                        <span key={i}>{part}</span>
                    ),
                )}
            </>
        );
    }

    const renderItem = (item: SelectItemOption) => {
        if (!textValue) return item.label;

        return highlightText(item.label, textValue);
    };

    return (
        <div style={{ display: 'flex', height: '400px' }}>
            <div style={{ width: '300px' }}>
                <Select
                    multiselect
                    variant="tight"
                    placeholder="Placeholder"
                    items={items}
                    listMaxHeight="300px"
                    renderItem={renderItem}
                    onToggle={(open) => {
                        if (open) {
                            setTextValue("");
                        }
                    }}
                    beforeList={<TextField placeholder="Введите 'Токио'" size="s" value={textValue} onChange={(e) => setTextValue(e.target.value)} contentRight={textValue && <IconCloseCircleOutline onClick={() => setTextValue("")} color="gray" size="xs" />} />}
                />
            </div>
        </div>
    );
}
```

## Клавиатурная навигация Клавиатурная навигация Данный компонент соответствует требования W3C:  Select  и частично  TreeView . `Tab`  - закрывает дропдаун. Перемещает фокус на следующий элемент на странице; `Enter`  - открывает/закрывает дропдаун. Если на элементе - выбирает его. Если у элемента есть дочерний дропдаун - открывает его, выбор элемента не происходит; `Space`  - открывает/закрывает дропдаун. Если на элементе - выбирает его и все дочерние элементы. `Home`  - открывает дропдаун и перемещает фокус на первый элемент; `End`  - открывает дропдаун и перемещает фокус на последний элемент; `PageUp`  - перемещает фокус на 10 элементов выше либо в начало списка; `PageDown`  - перемещает фокус на 10 элементов ниже либо в конце списка; `ArrowUp`  - открывает дропдаун и перемещает фокус на первый элемент. Перемещает фокус на один элемент выше; `ArrowDown`  - открывает дропдаун и перемещает фокус на первый элемент. Перемещает фокус на один элемент ниже; `ArrowRight`  - если фокус на элементе вложенного списка - открывает его и перемещает фокус на первый элемент; Если фокус на таргете - переходит в режим выбора чипа. `ArrowLeft`  - закрывает текущий список и перемещает фокус на предыдущий; Если фокус на таргете - переходит в режим выбора чипа. `Backspace`  - только если фокус на чипе - снимает выбор с текущего значения;

