        const selectRow = (rowId: string) => {
            setSelected({ ...selected, [rowId]: true });
        };

        return {
            data: sortedHelper(filterHelper(data, filtered), sorted),
            selected,
            filtered,
            sorted,
            onChange,
            deleteItem,
            updateRow,
            clearSelected,
            clearFiltered,
            clearSorted,
            clearAll,
