## Сценарии использования Сценарии использования ### Выделение строки по нажатию Выделение строки по нажатию Для осуществления этой цели существует свойство  `setRowProps` . Это функция, которая принимает объект строки  `row`  и возвращает объект атрибутов, которые будут прокинуты в тег  `<tr>` . ```tsx
    export function App() {
        const data = [
            {
                id: '0',
                country: 'Канада',
                capital: 'Оттава',
                population: 38,
            },
            {
                id: '1',
                country: 'Бразилия',
                capital: 'Бразилиа',
                population: 213,
            },
            {
                id: '2',
                country: 'Германия',
                capital: 'Берлин',
                population: 83,
            },
        ];

        const columns = [
            {
                id: 'country',
                label: 'Страна',
            },
            {
                id: 'capital',
                label: 'Столица',
            },
            {
                id: 'population',
                label: 'Население, млн',
            },
        ];

        const [rowHighlighted, setRowHighlighted] = React.useState(null);

        const setRowProps = (row: any) => {
            return {
                onClick: () => setRowHighlighted(row.id),
                style: rowHighlighted === row.id ? {
                    background: 'lightgray'
                } : undefined
            };
        };

        return (
            <Table data={data} columns={columns} setRowProps={setRowProps} />
        );
    }
```

