## API API Props (свойства) для компонента Table: [{"name":"view","type":{"name":"enum","raw":"\"clear\" | \"default\"","value":[{"value":"\"clear\""},{"value":"\"default\""}]}},{"name":"size","type":{"name":"enum","raw":"\"m\" | \"s\" | \"l\"","value":[{"value":"\"m\""},{"value":"\"s\""},{"value":"\"l\""}]}},{"name":"data","type":{"name":"TableRowData[]"}},{"name":"columns","type":{"name":"TableColumnData[]"}},{"name":"onChange","type":{"name":"((data: { selected: RowSelectionState; filtered: { id: string; value: unknown; }[]; sorted: { id: string; desc: boolean; }[] | undefined; }) => void) | undefined"}},{"name":"borderVariant","type":{"name":"enum","raw":"\"all\" | \"header\" | \"rows\"","value":[{"value":"\"all\""},{"value":"\"header\""},{"value":"\"rows\""}]}},{"name":"enableSelection","type":{"name":"boolean"}},{"name":"selected","type":{"name":"RowSelectionState"}},{"name":"filtered","type":{"name":"{ id: string; value: unknown; }[]"}},{"name":"sorted","type":{"name":"{ id: string; desc: boolean; }[]"}},{"name":"maxHeight","type":{"name":"MaxHeight<string | number>"}},{"name":"stickyHeader","type":{"name":"boolean"}},{"name":"onCellUpdate","type":{"name":"((rowId: string, columnId: string, value: unknown) => void)"}},{"name":"setRowProps","type":{"name":"((row: TableRowData) => HTMLAttributes<any> & ThHTMLAttributes<any>)"}},{"name":"topContent","type":{"name":"ReactNode"}},{"name":"bottomContent","type":{"name":"ReactNode"}},{"name":"loadingSlot","type":{"name":"ReactNode"}},{"name":"onScroll","type":{"name":"((e: UIEvent<HTMLElement, UIEvent>) => void)"}},{"name":"classNames","type":{"name":"{ root?: string; table?: string; header?: { wrapper?: string | undefined; row?: string | undefined; cell?: string | undefined; } | undefined; body?: { wrapper?: string | undefined; row?: string | undefined; cell?: string | undefined; } | undefined; } | undefined"}}] Обязательными полями являются  `data`  и  `columns` . Формат следующий: ```tsx
export type TableRowData = {
    /**
     * Уникальный идентификатор строки
     */
    id: string;
    /**
     * Неограниченный список пар ключ:значение, составляющих контент таблицы.
     * Должен совпадать с ключами из TableColumnData
     */
