### Подключение клавиатурной навигации Подключение клавиатурной навигации Для этого необходимо дополнительно прокинуть свойства  `index, itemIndex, onIndexChange` . 
Для горизонтальных табов: клавиши ArrowLeft, ArrowRight, Home, End для навигации по вкладкам. 
Для вертикальных табов: клавиши ArrowUp, ArrowDown, Home, End для навигации по вкладкам. ```tsx
import React, { useState } from 'react';
import { Tabs, TabItem } from '@salutejs/plasma-web';
import { IconClock } from '@salutejs/plasma-icons';

export function App() {
    const items = Array(4).fill(0);
    const [horizontalIndex, setHorizontalIndex] = useState(0);
    const [verticalIndex, setVerticalIndex] = useState(0);

    return (
        <div style={{ display: "flex", flexDirection: "column", gap: "50px"}}>
            <div>
                <Tabs view="divider" stretch size="xs" index={horizontalIndex}>
                    {items.map((_, i) => (
                        <TabItem
                            view="divider"
                            key={`item:${i}`}
                            size="xs"
                            itemIndex={i}
                            onIndexChange={(i) => setHorizontalIndex(i)}
                            selected={i === horizontalIndex}
                            tabIndex={0}
                            contentLeft={<IconClock size="xs" color="inherit" />}
                            onClick={() => setHorizontalIndex(i)}
                        >
                            {`Label${i + 1}`}
                        </TabItem>
                    ))}
                </Tabs>
            </div>

            <div>
                <Tabs orientation="vertical" view="divider" size="xs" index={verticalIndex}>
                    {items.map((_, i) => (
                        <TabItem
                            orientation="vertical"
                            view="divider"
                            key={`item:${i}`}
                            size="xs"
                            itemIndex={i}
                            onIndexChange={(i) => setVerticalIndex(i)}
                            selected={i === verticalIndex}
                            tabIndex={0}
                            contentLeft={<IconClock size="xs" color="inherit" />}
                            onClick={() => setVerticalIndex(i)}
                        >
                            {`Label${i + 1}`}
                        </TabItem>
                    ))}
                </Tabs>
            </div>
        </div>
    );
}
```

