Свойства  `rows`  и  `cols`  указываются в абсолютных единицах, отвечают за фиксированное количество строк и столбцов. ```tsx
import React from 'react';
import { TextArea } from '@salutejs/plasma-web';

export function App() {
    return (
        <div>
            <TextArea
                placeholder="Введите значение"
                defaultValue="Значение"
                rows={5}
                cols={20}
            />
        </div>
    );
}
```

### Autoresize Autoresize Также можно включить автоматическое регулирование высоты поля ввода по длине контента внутри (параметра  `value` ).
Для этого необходимо использовать свойство  `autoResize` . Свойства  `minAuto` ,  `maxAuto`  указываются в абсолютных единицах и отвечают за минимальное и максимальное количество строк. ```tsx
import React from 'react';
import { TextArea } from '@salutejs/plasma-web';

export function App() {
    const [value, setValue] = React.useState('Значение');

    return (
        <div>
            <TextArea
                placeholder="Введите значение"
                value={value}
                onChange={(e) => {
                    setValue(e.target.value);
                }}
                autoResize
                minAuto={3}
                maxAuto={5}
            />
        </div>
    );
}
```

### Подсказки Подсказки Для вывода подсказки снизу от поля используйте свойство  `leftHelper`  и/или  `rightHelper` ,
для подсказки в виде Tooltip -  `hintText` , для подсказки сверху справа -  `titleCaption` : ```tsx
import React from 'react';
import { TextArea } from '@salutejs/plasma-web';

export function App() {
    return (
        <div>
            <TextArea
                placeholder="Введите значение"
                defaultValue="Значение"
                leftHelper="Подсказка снизу слева"
                rightHelper="Подсказка снизу справа"
                titleCaption="Подсказка сверху"
                hintText="Подсказка в виде Tooltip"
                hintView="default"
                hintSize="m"
            />
        </div>
    );
}
```

### Обязательность поля Обязательность поля :::tip
Наличие индикатора регулируется свойством  `hasRequiredIndicator` .
::: Обязательность поля задаётся с помощью свойства  `required` .
Если поле является обязательным, то у компонента появляется специальный индикатор.
Изменить расположение индикатора можно с помощью свойства  `requiredPlacement` , которое принимает значения  `left`  и  `right` . ```tsx
import React from 'react';
import { TextArea } from '@salutejs/plasma-web';
import { IconDownload } from '@salutejs/plasma-icons';

export function App() {
    return (
        <div>
            <TextArea
                hasRequiredIndicator
                required
                requiredPlacement="right"
                label="Лейбл"
                leftHelper="Подсказка к полю"
                placeholder="Введите значение"
                contentRight={<IconDownload />}
            />
        </div>
    );
}
```

### Слот для контента над вводимым текстом Слот для контента над вводимым текстом Слот для контента над вводимым текстом задается с помощью свойства  `headerSlot` : ```tsx
import React from 'react';
import { TextArea, TextS } from '@salutejs/plasma-web';
import { surfaceSolid03 } from '@salutejs/plasma-tokens-web';

export function App() {
    const HeaderSlot = () => (
       <div style={{ margin: "0 0.75rem", padding: "0.5rem 0", borderBottom: `0.063rem solid ${surfaceSolid03}` }}>
           <TextS>Дополнительный контент</TextS>
       </div>
    )

    return (
        <div>
            <TextArea
                headerSlot={<HeaderSlot />}
                placeholder="Введите значение"
                defaultValue="Значение"
                leftHelper="Подсказка снизу слева"
            />
        </div>
    );
}
```

