### Ориентация TextFieldGroup и отступы между TextField Ориентация TextFieldGroup и отступы между TextField TextFieldGroup может располагаться вертикально или горизонтально и иметь два вида отступов, в зависимости от shape.
При  `shape='default'` ,  `gap`  может принимать значения  `dense`  и  `wide` ;
При  `shape='segmented'` ,  `gap`  может принимать значения  `none`  и  `dense` ; ```tsx
import React from 'react';
import { TextFieldGroup, TextField } from '@salutejs/plasma-web';

export function App() {
    return (
        <div>
            <TextFieldGroup size="xs" orientation="vertical" shape="segmented" gap="none">
                {Array(5)
                    .fill(true)
                    .map((_, i) => (
                        <TextField placeholder={`input #${i}`} />
                    ))}
            </TextFieldGroup>

            <TextFieldGroup size="xs" orientation="horizontal" gap="wide">
                {Array(4)
                    .fill(true)
                    .map((_, i) => (
                        <TextField placeholder={`input #${i}`} />
                    ))}
            </TextFieldGroup>
        </div>
    );
}
```

