            <TimePicker view="default" size="m" placeholder="Средний размер" />
            <TimePicker view="default" size="s" placeholder="Маленький размер" />
            <TimePicker view="default" size="xs" placeholder="Очень маленький размер" />
        </div>
    );
}
```

