:{"name":"boolean"}},{"name":"onDragStart","type":{"name":"((info: NodeDragEventParams) => void)"}},{"name":"onDragEnter","type":{"name":"((info: NodeDragEventParams & { expandedKeys: Key[]; }) => void)"}},{"name":"onDragOver","type":{"name":"((info: NodeDragEventParams) => void)"}},{"name":"onDragLeave","type":{"name":"((info: NodeDragEventParams) => void)"}},{"name":"onDragEnd","type":{"name":"((info: NodeDragEventParams) => void)"}},{"name":"onDrop","type":{"name":"((info: NodeDragEventParams & { dragNode: EventDataNode; dragNodesKeys: Key[]; dropPosition: number; dropToGap: boolean; }) => void)"}},{"name":"allowDrop","type":{"name":"((options: AllowDropOptions) => boolean)"}},{"name":"loadData","type":{"name":"((treeNode: EventDataNode) => Promise<any>)"}},{"name":"onLoadData","type":{"name":"((loadedKeys: Key[], info: LoadInfo) => void)"}},{"name":"variant","type":{"name":"enum","raw":"\"normal\" | \"tight\"","value":[{"value":"\"normal\""},{"value":"\"tight\""}]}}] Обязательным параметром является только массив  `items` . Формат следующий: ```tsx
