    return (
        <section>
            <UploadVisual
                items={items}
                status={state.status}
                progress={state.progress}
                message={state.message}
                onChange={onChange}
                onItemAction={onItemRemove}
                onItemsSortEnd={onItemsSortEnd}
                onValidation={onValidation}
                interactionType="draggable"
            />
        </section>
    );
}
